Rules.InvariantScript:
Patch(CRUserAdmin, ThisItem, {
  Role: {Value: ddlRoleUAS.Selected.Value},
  StakeholderGroup: {Value: ddlGroupUAS.Selected.Value},
  IsActive: tglActiveUAS.Value
